import { Type } from '@sinclair/typebox';
import { silSchema } from '../../../schemas/sil.js';
import { parse } from '../../../utils/json.js';
export const parseRawServerServerItemOptionValue = (value) => {
    if (typeof value !== 'string')
        return;
    return parse(value, Type.Union([silSchema, Type.Null()]));
};
export const normalizeServerServerItemOptionValue = (value, option) => (value !== undefined ? value : option.def);
export const serializeServerServerItemOptionValue = (value) => JSON.stringify(value);
export const toServerServerItemOption = (localize, query, option) => ({
    query,
    name: localize(option.name),
    description: option.description && localize(option.description),
    required: option.required,
    type: option.type,
    itemType: option.itemType,
    def: option.def,
    allowOtherServers: option.allowOtherServers,
});
